import{_ as t,o as e,c as r,ai as l}from"./chunks/framework.SowO7O0D.js";const c=JSON.parse('{"title":"第十七课：止损与止盈","description":"","frontmatter":{},"headers":[],"relativePath":"guide/17-stop-loss.md","filePath":"guide/17-stop-loss.md","lastUpdated":0}'),s={name:"guide/17-stop-loss.md"};function o(d,a,n,i,h,p){return e(),r("div",null,[...a[0]||(a[0]=[l(`<h1 id="第十七课-止损与止盈" tabindex="-1">第十七课：止损与止盈 <a class="header-anchor" href="#第十七课-止损与止盈" aria-label="Permalink to “第十七课：止损与止盈”">​</a></h1><p><strong>会买是徒弟，会卖才是师傅。</strong> 这一课讲如何体面地离场。</p><h2 id="一、为什么要止损" tabindex="-1">一、为什么要止损？ <a class="header-anchor" href="#一、为什么要止损" aria-label="Permalink to “一、为什么要止损？”">​</a></h2><blockquote><p><strong>止损不是为了赚钱，而是为了控制亏损。</strong></p></blockquote><h3 id="数字告诉你止损的重要性" tabindex="-1">数字告诉你止损的重要性 <a class="header-anchor" href="#数字告诉你止损的重要性" aria-label="Permalink to “数字告诉你止损的重要性”">​</a></h3><table tabindex="0"><thead><tr><th>亏损幅度</th><th>回本需要涨多少</th></tr></thead><tbody><tr><td>10%</td><td>11%</td></tr><tr><td>20%</td><td>25%</td></tr><tr><td>30%</td><td>43%</td></tr><tr><td>50%</td><td>100%</td></tr><tr><td>80%</td><td>400%</td></tr></tbody></table><blockquote><p>💡 亏得越多，回本越难。<strong>及时止损是保护本金最有效的方式。</strong></p></blockquote><h2 id="二、止损的方法" tabindex="-1">二、止损的方法 <a class="header-anchor" href="#二、止损的方法" aria-label="Permalink to “二、止损的方法”">​</a></h2><h3 id="方法1-固定比例止损" tabindex="-1">方法1：固定比例止损 <a class="header-anchor" href="#方法1-固定比例止损" aria-label="Permalink to “方法1：固定比例止损”">​</a></h3><p>亏到某个比例就卖，比如<strong>-8%</strong>。</p><blockquote><p>10元买的，8元止损（亏20%就卖）</p></blockquote><h3 id="方法2-技术位止损" tabindex="-1">方法2：技术位止损 <a class="header-anchor" href="#方法2-技术位止损" aria-label="Permalink to “方法2：技术位止损”">​</a></h3><p>跌破重要支撑位就卖。</p><blockquote><p>股价跌破20日均线，止损</p></blockquote><h3 id="方法3-逻辑止损" tabindex="-1">方法3：逻辑止损 <a class="header-anchor" href="#方法3-逻辑止损" aria-label="Permalink to “方法3：逻辑止损”">​</a></h3><p>买入的理由消失了，就卖。</p><blockquote><p>买的时候看好业绩增长，结果业绩暴雷，马上卖</p></blockquote><h2 id="三、止损的常见误区" tabindex="-1">三、止损的常见误区 <a class="header-anchor" href="#三、止损的常见误区" aria-label="Permalink to “三、止损的常见误区”">​</a></h2><blockquote><p>⚠️ <strong>这些止损方式是错的！</strong></p></blockquote><table tabindex="0"><thead><tr><th>误区</th><th>问题</th></tr></thead><tbody><tr><td>跌了不卖，等反弹</td><td>小亏变大亏</td></tr><tr><td>跌了就补仓，越跌越买</td><td>可能越陷越深</td></tr><tr><td>止损设太宽</td><td>亏太多，难以回本</td></tr><tr><td>止损设太窄</td><td>被市场噪音频繁止损</td></tr></tbody></table><h2 id="四、什么是止盈" tabindex="-1">四、什么是止盈？ <a class="header-anchor" href="#四、什么是止盈" aria-label="Permalink to “四、什么是止盈？”">​</a></h2><p><strong>止盈 = 赚钱了，卖不卖？</strong></p><p>涨的时候要学会&quot;落袋为安&quot;，不然只是&quot;纸上富贵&quot;。</p><h2 id="五、止盈的方法" tabindex="-1">五、止盈的方法 <a class="header-anchor" href="#五、止盈的方法" aria-label="Permalink to “五、止盈的方法”">​</a></h2><h3 id="方法1-目标收益率止盈" tabindex="-1">方法1：目标收益率止盈 <a class="header-anchor" href="#方法1-目标收益率止盈" aria-label="Permalink to “方法1：目标收益率止盈”">​</a></h3><p>达到目标收益就卖：</p><table tabindex="0"><thead><tr><th>投资类型</th><th>建议目标</th></tr></thead><tbody><tr><td>短线</td><td>10-15%</td></tr><tr><td>中线</td><td>20-30%</td></tr><tr><td>长线</td><td>50%+</td></tr></tbody></table><h3 id="方法2-分批止盈" tabindex="-1">方法2：分批止盈 <a class="header-anchor" href="#方法2-分批止盈" aria-label="Permalink to “方法2：分批止盈”">​</a></h3><p>涨到目标后，分批卖出：</p><ul><li>第一次止盈：卖1/3</li><li>第二次止盈：再卖1/3</li><li>剩下的继续持有</li></ul><h3 id="方法3-高处回落止盈" tabindex="-1">方法3：高处回落止盈 <a class="header-anchor" href="#方法3-高处回落止盈" aria-label="Permalink to “方法3：高处回落止盈”">​</a></h3><p>从最高点回落<strong>15-20%</strong>就清仓。</p><blockquote><p>💡 适合：<strong>不知道涨到哪里是顶</strong>的情况。</p></blockquote><h2 id="六、止损-vs-不止损" tabindex="-1">六、止损 vs 不止损 <a class="header-anchor" href="#六、止损-vs-不止损" aria-label="Permalink to “六、止损 vs 不止损”">​</a></h2><h3 id="不止损的人在想什么" tabindex="-1">不止损的人在想什么？ <a class="header-anchor" href="#不止损的人在想什么" aria-label="Permalink to “不止损的人在想什么？”">​</a></h3><ul><li>&quot;再等等，肯定会反弹&quot;</li><li>&quot;卖了就真亏了&quot;</li><li>&quot;我不卖，就不算亏&quot;</li></ul><blockquote><p>🚨 <strong>这是散户最常见的错误</strong>，鸵鸟心态只会让亏损越来越大。</p></blockquote><h2 id="七、止损-止盈纪律" tabindex="-1">七、止损/止盈纪律 <a class="header-anchor" href="#七、止损-止盈纪律" aria-label="Permalink to “七、止损/止盈纪律”">​</a></h2><blockquote><p>记住：<strong>制定计划，严格执行</strong>。</p></blockquote><div class="language- line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>买入前想好：</span></span>
<span class="line"><span>- 止损位在哪？（比如-8%）</span></span>
<span class="line"><span>- 目标位在哪？（比如+20%）</span></span>
<span class="line"><span>- 什么情况下提前止盈？</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><p>到了位置就执行，不要临时改计划。</p><h2 id="思考题" tabindex="-1">思考题 <a class="header-anchor" href="#思考题" aria-label="Permalink to “思考题”">​</a></h2><blockquote><p>你10元买了某股票，现在涨到13元（+30%）。你会止盈吗？如果继续涨到15元呢？</p></blockquote><hr><p><strong>下一课预告</strong>：风险控制学完了，下一课学习<strong>选股思路</strong>——如何从4000只股票中选出你要买的。</p>`,45)])])}const u=t(s,[["render",o]]);export{c as __pageData,u as default};
